  ('bookkeeper-moex-02079', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，核准由總機構合併申報銷售額、應納或溢付營業稅額者，其所有其 他固定營業場所：', '["仍應向所在地主管稽徵機關申報銷售額及進項憑證", "仍應向所在地主管稽徵機關申報銷售額，但無須申報進項憑證", "仍應向所在地主管稽徵機關申報進項憑證，但無須申報銷售額", "無須另行申報"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02080', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '靡葫公司銷售商品一批，售價1,200,000元。銷售時未依法開立統一發票，且於申報當期銷售額時亦未列 入申報，違反加值型及非加值型營業稅法第51條第3款規定，據稅務違章案件裁罰金額或倍數參考表， 應按所漏稅額處三倍之漏稅罰；另該公司未依法給與憑證，違反稅捐稽徵法第44 條規定，應依規定處以 行為罰。本案件應裁處之罰鍰金額為多少？', '["600,000元", "300,000元", "240,000元", "180,000元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02081', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '山明公司進貨一批100,000元，數日後以售價120,000元（不含稅）銷售予水秀公司。若買賣雙方為按一般 稅額計稅之營業人，則依加值型及非加值型營業稅法之規定水秀公司須支付予山明公司之稅額為多少元？', '["6,000元", "5,000元", "1,000元", "0元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02082', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列有關經營衍生性金融商品、公司債、金融債券之營業稅，何者 敘述正確？', '["銷售額、佣金及手續費均免稅", "銷售額免稅，佣金及手續費應稅", "銷售額應稅，佣金及手續費免稅", "銷售額、佣金及手續費均應稅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02083', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列何情況營業人僅須向主管稽徵機關申報核備，不須再申請登記？', '["設立", "合併", "變更", "復業"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02084', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '中古車商三民公司於99年5月以210,000元向四維保險公司購入舊乘人小汽車乙輛，於99年11月出售 該汽車，售價140,000元，銷項稅額7,000元。依加值型及非加值型營業稅法規定，三民公司於申報該汽 車銷售額之當期，可申報扣抵該汽車之銷項稅額為多少元？', '["7,000元", "10,000元", "105,000元", "0元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02085', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，營業人未依規定期限申報銷售額或統一發票明細表，其逾三十日者， 按核定應納稅額加徵多少怠報金？', '["3‰", "1%", "3%", "30%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 41, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02086', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關法規規定，營業人以貨物或勞務與他人交換貨物或勞務者，其銷售 額應如何認定？', '["以換出貨物之時價認定", "以換入貨物之時價認定", "以換出或換入貨物之時價，從高認定", "以換出或換入貨物之時價，從低認定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 42, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02087', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關法規規定，下列何者之進項稅額得扣抵銷項稅額？', '["因辦理員工伙食購買主、副食等之進項稅額", "購置供工作場所穿著之工作服之進項稅額", "贈送股東紀念品之進項稅額", "對外國政府捐贈之進項稅額"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 43, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02088', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '某餐飲業為按一般稅額計稅之營業人，其向顧客收取餐飲費6,300元並加收一成服務費630元，依加值型 及非加值型營業稅法及相關法規規定，該筆交易之銷售額為多少元？', '["6,000元", "6,300元", "6,600元", "6,930元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 44, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
